const headers = $json.headers ?? {};
const expectedToken = $env.N8N_WEBHOOK_SHARED_TOKEN;
if (typeof expectedToken !== 'string' || expectedToken.length === 0) {
  throw new Error('Server misconfigured: N8N_WEBHOOK_SHARED_TOKEN is missing');
}
let providedToken = '';
for (const [key, value] of Object.entries(headers)) {
  if (typeof key === 'string' && key.toLowerCase() === 'x-jenkins-webhook-token') {
    providedToken = Array.isArray(value) ? String(value[0] ?? '') : String(value ?? '');
    break;
  }
}
if (providedToken !== expectedToken) {
  throw new Error('Unauthorized webhook token');
}
const body = $json.body ?? $json;
const required = ['job_name', 'build_number', 'status'];
const missing = required.filter((key) => body[key] === undefined || body[key] === null || body[key] === '');
if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}
const buildNumber = Number(body.build_number);
if (!Number.isInteger(buildNumber) || buildNumber < 0) {
  throw new Error('Invalid build_number: must be a non-negative integer');
}
if (typeof body.status !== 'string' || body.status.trim().length === 0) {
  throw new Error('Invalid status: must be a non-empty string');
}
const durationRaw = body.duration_ms;
const durationMs = durationRaw === undefined || durationRaw === null || durationRaw === '' ? null : Number(durationRaw);
if (durationMs !== null && !Number.isFinite(durationMs)) {
  throw new Error('Invalid duration_ms: must be numeric when provided');
}
return [{
  json: {
    ...body,
    build_number: buildNumber,
    status: body.status.trim(),
    duration_ms: durationMs,
  },
}];

